use std::collections::HashMap;

struct KeywordMatcher {
    patterns: Vec<String>,
}

impl KeywordMatcher {
    fn new(patterns: Vec<&str>) -> Self {
        KeywordMatcher { patterns: patterns.iter().map(|&s| s.to_string()).collect() }
    }

    fn find_all_matches(&self, text: &str) -> HashMap<String, usize> {
        let mut matches: HashMap<String, usize> = HashMap::new();

        for pattern in &self.patterns {
            if let Some(index) = text.find(pattern) {
                matches.entry(pattern.clone()).or_insert(0);
                *matches.get_mut(&pattern.clone()).unwrap() += index;
            }
        }

        let mut final_counts: HashMap<String, usize> = HashMap::new();
        for (key, total) in matches.into_iter() {
            final_counts.insert(key, total);
        }
        final_counts
    }
}

fn main() {
    let search_patterns = vec!["error", "timeout", "fail"];
    let matcher = KeywordMatcher::new(search_patterns);

    let document_text = "Connection error detected with timeout. Please retry.";

    let results = matcher.find_all_matches(document_text);

    println!("Found matches in the document:");
    for (pattern, count) in &results {
        println!("- Pattern \"{}\": Found at least once (Total recorded index: {})", pattern, count);
    }
}

use std::collections::HashMap;

struct PacketSniffer {
    signatures: Vec<String>,
}

impl PacketSniffer {
    fn new(signatures: Vec<&str>) -> Self {
        PacketSniffer { signatures: signatures.iter().map(|&s| s.to_string()).collect() }
    }

    fn scan_packet(&self, data: &str) -> Vec<String> {
        let mut found_matches = Vec::new();
        for signature in &self.signatures {
            if let Some(start) = data.find(signature) {
                let _match_span = &data[start..];
                found_matches.push(format!("Found '{}' starting at offset {}", signature, start));
                break
            }
        }
        found_matches
    }
}

fn main() {
    let bad_sigs = vec!["malware_id", "suspicious_header", "admin_bypass_key"];
    let sniffer = PacketSniffer::new(bad_sigs.iter().map(|&s| s).collect());
    let packet_data = "[INFO] Connection established. Payload contains malware_id signature detected.";
    let results = sniffer.scan_packet(packet_data);
    for result in results {
        println!("ALERT: {}", result);
    }
}
